 */
export function httpRequestError(
  reason: HttpRequestError["reason"],
  request: HttpRequest,
  message: string,
  cause?: unknown,
): HttpRequestError {
  return Object.freeze({
    _tag: "HttpRequestError" as const,
    reason,
    request,
    message,
    cause,
  });
}

